// // This module increments the counter on each positive clock edge and resets to 0 when the reset signal is active.
module down_counter_8 
(
  input rst,
  input clk,

  output reg [7:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 8'b11111111;
    end 

	else 
	begin
      count <= count - 1;
    end
  end

endmodule
